class Solution {
public:
int maxSubarraySum(int arr[], int n) {
	if (n == 0) {
		return 0;
	}
	int maxSum = arr[0];
	int currentSum = arr[0];
	for (int i = 1; i < n; i++) {
		currentSum = std::max(arr[i], currentSum + arr[i]);
		maxSum = std::max(maxSum, currentSum);
	}
	return maxSum;
}

