// Solution
import sys

class Solution:
    def maxSubarraySum(self, arr, n):
        if n == 0:
            return 0
        maxSum = arr[0]
        currentSum = arr[0]
        for i in range(1, n):
            currentSum = max(arr[i], currentSum + arr[i])
            maxSum = max(maxSum, currentSum)
        return maxSum

if __name__ == '__main__':
    Solution = Solution()
    arr = list(map(int, input().split()))
    n = len(arr)
    res = Solution.maxSubarraySum(arr, n)
    print(res)

